#ifndef KERNEL_H
#define KERNEL_H

#include <cuda_runtime.h>
#include <cuda_bf16.h>

// Constants for this specific configuration
constexpr int NUM_QO_HEADS = 32;
constexpr int NUM_KV_HEADS = 8;
constexpr int HEAD_DIM = 128;
constexpr int GQA_RATIO = NUM_QO_HEADS / NUM_KV_HEADS;  // 4
constexpr int BLOCK_SIZE = 128;
constexpr int TILE_SIZE = 64;

// Kernel function declaration
void launch_gqa_ragged_prefill_causal_kernel(
    const void* q_ptr,
    const void* k_ptr,
    const void* v_ptr,
    const int* qo_indptr_ptr,
    const int* kv_indptr_ptr,
    float sm_scale,
    void* output_ptr,
    float* lse_ptr,
    int total_q,
    int total_kv,
    int len_indptr
);

// Host wrapper function
void run_gqa_ragged_prefill_causal(
    const void* q_ptr,
    const void* k_ptr,
    const void* v_ptr,
    const int* qo_indptr_ptr,
    const int* kv_indptr_ptr,
    float sm_scale,
    void* output_ptr,
    float* lse_ptr,
    int total_q,
    int total_kv,
    int len_indptr
);

#endif // KERNEL_H

#include "kernel.h"
#include <device_launch_parameters.h>
#include <math_constants.h>
#include <stdio.h>

__global__ void gqa_ragged_prefill_causal_kernel(
    const __nv_bfloat16* __restrict__ q,
    const __nv_bfloat16* __restrict__ k,
    const __nv_bfloat16* __restrict__ v,
    const int* __restrict__ qo_indptr,
    const int* __restrict__ kv_indptr,
    float sm_scale,
    __nv_bfloat16* __restrict__ output,
    float* __restrict__ lse,
    int total_q,
    int total_kv,
    int len_indptr
) {
    int q_idx = blockIdx.x * blockDim.x + threadIdx.x;
    if (q_idx >= total_q) return;

    int tid = threadIdx.x;
    int num_threads = blockDim.x;

    // Find which sequence this query token belongs to (binary search on qo_indptr)
    int lo = 0, hi = len_indptr - 1;
    while (lo < hi) {
        int mid = (lo + hi) / 2;
        if (qo_indptr[mid] <= q_idx) {
            lo = mid + 1;
        } else {
            hi = mid;
        }
    }
    int seq_idx = lo - 1;
    int q_start = qo_indptr[seq_idx];
    int q_end = qo_indptr[seq_idx + 1];
    int kv_start = kv_indptr[seq_idx];
    int kv_end = kv_indptr[seq_idx + 1];

    int num_q_tokens = q_end - q_start;
    int num_kv_tokens = kv_end - kv_start;
    int delta = num_kv_tokens - num_q_tokens;
    int q_local_idx = q_idx - q_start;

    // Each thread handles one Q head
    for (int head = tid; head < NUM_QO_HEADS; head += num_threads) {
        int kv_head = head / GQA_RATIO;

        // Load Q vector for this token and head
        float q_vec[HEAD_DIM];
        int q_offset = (q_idx * NUM_QO_HEADS + head) * HEAD_DIM;
        for (int d = 0; d < HEAD_DIM; d++) {
            q_vec[d] = __bfloat162float(q[q_offset + d]);
        }

        // Online softmax state
        float max_score = -INFINITY;
        float sum_exp = 0.0f;
        float output_vec[HEAD_DIM] = {0};

        // Process all KV tokens
        for (int kv_local_idx = 0; kv_local_idx < num_kv_tokens; kv_local_idx++) {
            // Causal mask: kv_local_idx < q_local_idx + 1 + delta
            // This means we can attend to KV positions [0, q_local_idx + delta]
            if (kv_local_idx > q_local_idx + delta) {
                continue;
            }

            int kv_global = kv_start + kv_local_idx;
            int kv_offset = (kv_global * NUM_KV_HEADS + kv_head) * HEAD_DIM;

            // Load K and V
            float k_val[HEAD_DIM];
            float v_val[HEAD_DIM];
            for (int d = 0; d < HEAD_DIM; d++) {
                k_val[d] = __bfloat162float(k[kv_offset + d]);
                v_val[d] = __bfloat162float(v[kv_offset + d]);
            }

            // Compute dot product Q @ K
            float score = 0.0f;
            for (int d = 0; d < HEAD_DIM; d++) {
                score += q_vec[d] * k_val[d];
            }
            score *= sm_scale;

            // Update online softmax
            if (score > max_score) {
                float scale = expf(max_score - score);
                sum_exp *= scale;
                for (int d = 0; d < HEAD_DIM; d++) {
                    output_vec[d] *= scale;
                }
                max_score = score;
            }
            float weight = expf(score - max_score);
            sum_exp += weight;
            for (int d = 0; d < HEAD_DIM; d++) {
                output_vec[d] += weight * v_val[d];
            }
        }

        // Normalize output
        if (sum_exp > 0.0f) {
            float norm = 1.0f / sum_exp;
            for (int d = 0; d < HEAD_DIM; d++) {
                output_vec[d] *= norm;
            }
        }

        // Write output
        int out_offset = (q_idx * NUM_QO_HEADS + head) * HEAD_DIM;
        for (int d = 0; d < HEAD_DIM; d++) {
            output[out_offset + d] = __float2bfloat16(output_vec[d]);
        }

        // Write LSE (2-base log-sum-exp)
        // Each thread writes its own head's LSE
        lse[q_idx * NUM_QO_HEADS + head] = max_score / logf(2.0f);
    }
}

void launch_gqa_ragged_prefill_causal_kernel(
    const void* q_ptr,
    const void* k_ptr,
    const void* v_ptr,
    const int* qo_indptr_ptr,
    const int* kv_indptr_ptr,
    float sm_scale,
    void* output_ptr,
    float* lse_ptr,
    int total_q,
    int total_kv,
    int len_indptr
) {
    int num_threads = BLOCK_SIZE;
    int num_blocks = (total_q + num_threads - 1) / num_threads;

    gqa_ragged_prefill_causal_kernel<<<num_blocks, num_threads>>>(
        reinterpret_cast<const __nv_bfloat16*>(q_ptr),
        reinterpret_cast<const __nv_bfloat16*>(k_ptr),
        reinterpret_cast<const __nv_bfloat16*>(v_ptr),
        qo_indptr_ptr,
        kv_indptr_ptr,
        sm_scale,
        reinterpret_cast<__nv_bfloat16*>(output_ptr),
        lse_ptr,
        total_q,
        total_kv,
        len_indptr
    );

    cudaError_t err = cudaGetLastError();
    if (err != cudaSuccess) {
        fprintf(stderr, "CUDA kernel launch error: %s\n", cudaGetErrorString(err));
    }
}

void run_gqa_ragged_prefill_causal(
    const void* q_ptr,
    const void* k_ptr,
    const void* v_ptr,
    const int* qo_indptr_ptr,
    const int* kv_indptr_ptr,
    float sm_scale,
    void* output_ptr,
    float* lse_ptr,
    int total_q,
    int total_kv,
    int len_indptr
) {
    launch_gqa_ragged_prefill_causal_kernel(
        q_ptr, k_ptr, v_ptr,
        qo_indptr_ptr, kv_indptr_ptr,
        sm_scale, output_ptr, lse_ptr,
        total_q, total_kv, len_indptr
    );
}

#include <torch/extension.h>
#include <torch/types.h>
#include <ATen/cuda/CUDAContext.h>
#include <cuda_runtime.h>
#include "kernel.h"
#include <stdexcept>
#include <string>
#include <limits>
#include <cuda_bf16.h>

// Helper function to check tensor properties
void check_tensor(const torch::Tensor& tensor, const std::string& name) {
    TORCH_CHECK(tensor.is_cuda(), name + " must be on CUDA device");
    TORCH_CHECK(tensor.is_contiguous(), name + " must be contiguous");
}

// Main run function that can be called from Python
std::vector<torch::Tensor> run(
    const torch::Tensor& q,
    const torch::Tensor& k,
    const torch::Tensor& v,
    const torch::Tensor& qo_indptr,
    const torch::Tensor& kv_indptr,
    float sm_scale
) {
    // Validate input tensors
    check_tensor(q, "q");
    check_tensor(k, "k");
    check_tensor(v, "v");
    check_tensor(qo_indptr, "qo_indptr");
    check_tensor(kv_indptr, "kv_indptr");

    // Check dtypes
    TORCH_CHECK(q.dtype() == torch::kBFloat16, 
                "q must have dtype kBFloat16 but got " + torch::str(q.dtype()));
    TORCH_CHECK(k.dtype() == torch::kBFloat16, 
                "k must have dtype kBFloat16 but got " + torch::str(k.dtype()));
    TORCH_CHECK(v.dtype() == torch::kBFloat16, 
                "v must have dtype kBFloat16 but got " + torch::str(v.dtype()));
    TORCH_CHECK(qo_indptr.dtype() == torch::kInt32, 
                "qo_indptr must have dtype kInt32 but got " + torch::str(qo_indptr.dtype()));
    TORCH_CHECK(kv_indptr.dtype() == torch::kInt32, 
                "kv_indptr must have dtype kInt32 but got " + torch::str(kv_indptr.dtype()));

    // Get tensor dimensions
    int total_q = q.size(0);
    int num_qo_heads = q.size(1);
    int head_dim = q.size(2);
    int total_kv = k.size(0);
    int num_kv_heads = k.size(1);
    int len_indptr = qo_indptr.size(0);

    // Validate constants
    TORCH_CHECK(num_qo_heads == 32, "num_qo_heads must be 32, got " + std::to_string(num_qo_heads));
    TORCH_CHECK(num_kv_heads == 8, "num_kv_heads must be 8, got " + std::to_string(num_kv_heads));
    TORCH_CHECK(head_dim == 128, "head_dim must be 128, got " + std::to_string(head_dim));

    // Validate constraints
    int qo_last = qo_indptr[len_indptr - 1].item<int>();
    int kv_last = kv_indptr[len_indptr - 1].item<int>();
    TORCH_CHECK(total_q == qo_last, "total_q must equal qo_indptr[-1]");
    TORCH_CHECK(total_kv == kv_last, "total_kv must equal kv_indptr[-1]");

    // Create output tensors
    torch::Tensor output = torch::zeros(
        {total_q, num_qo_heads, head_dim},
        torch::TensorOptions().dtype(torch::kBFloat16).device(q.device())
    );

    torch::Tensor lse = torch::full(
        {total_q, num_qo_heads},
        -std::numeric_limits<float>::infinity(),
        torch::TensorOptions().dtype(torch::kFloat32).device(q.device())
    );

    // Get raw pointers
    const void* q_ptr = q.data_ptr();
    const void* k_ptr = k.data_ptr();
    const void* v_ptr = v.data_ptr();
    const int* qo_indptr_ptr = qo_indptr.data_ptr<int>();
    const int* kv_indptr_ptr = kv_indptr.data_ptr<int>();
    void* output_ptr = output.data_ptr();
    float* lse_ptr = lse.data_ptr<float>();

    // Launch kernel
    run_gqa_ragged_prefill_causal(
        q_ptr, k_ptr, v_ptr,
        qo_indptr_ptr, kv_indptr_ptr,
        sm_scale, output_ptr, lse_ptr,
        total_q, total_kv, len_indptr
    );

    // Synchronize to ensure completion
    cudaError_t err = cudaDeviceSynchronize();
    if (err != cudaSuccess) {
        throw std::runtime_error(std::string("CUDA synchronization error: ") + cudaGetErrorString(err));
    }

    return {output, lse};
}

PYBIND11_MODULE(TORCH_EXTENSION_NAME, m) {
    m.def("run", &run, "GQA Ragged Prefill Causal Attention Kernel");
}
